  (potentialVerticalStrips mu).filter (fun f =>
    isWeaklyDecreasing f ∧ isVerticalStripFun f mu.parts ∧ hasSizeDiff mu.parts f n
  ) |>.attach.image (fun ⟨f, hf⟩ =>
    let hf' := Finset.mem_filter.mp hf
